import './Navbar.css';

function Navbar() {
  return (
    <div className='navbar' id='navbar'>
      <div className='container'>
        <ul className='nav'>
          <li>Home</li>
          <li>Movies</li>
          <li>TV Shows</li>
          <li>My List</li>  
        </ul>
      </div>
    </div>
  );
}

export default Navbar;
